  id: "building-a-self-care-routine",
  slug: "building-a-self-care-routine",
  title: "Building a Self-Care Routine: A Foundation for Long-Term Mental Wellness",
  category: "Mental Health",
  categorySlug: "mental-health",
  aliases: ["self-care-mental-health-plan"],
  description: "A comprehensive guide to creating a sustainable self-care routine that supports emotional balance and mental resilience.",
