    src="https://images.unsplash.com/photo-1550831107-1553da8c8464?auto=format&fit=crop&w=1200&q=80&fm=webp&unique=2053"
    alt="Genetic testing analysis"
    loading="lazy"
    style="max-width:100%; border-radius:12px;"
