    id: "womens-wellness",
    slug: "womens-wellness",
    title: "Women's Wellness: Health Across All Life Stages",
    category: "Wellness",
    categorySlug: "wellness",
    description: "Comprehensive guide to women's health covering reproductive, hormonal, cardiovascular, and mental wellness strategies for every life stage.",
    author: "SixHealth Editorial Team",
    reviewer: "SixHealth Clinical Team",
